import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ProfileData {
  username: string;
  followers: number;
  engagementRate: number;
}

interface WeeklyGrowth {
  day: string;
  growth: number;
}

interface SocialMediaStatsData {
  profile: ProfileData;
  weeklyGrowth: WeeklyGrowth[];
  growthTrend: number[];
}

export default function Widget() {
  const data = response.data as SocialMediaStatsData;
  const { profile, weeklyGrowth, growthTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF' }}>
              {profile.username}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Followers: {profile.followers.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Engagement Rate: {profile.engagementRate}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: growthTrend,
                  color: '#1DA1F2',
                  label: 'Follower Growth',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyGrowth.map((d) => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'followers' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="followers"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
